-- Records of chart
-- ----------------------------
INSERT INTO `chart` VALUES (1984247027439013889, '用户增长表', '分析网站的增长情况', 'wait', '日期,新注册用户数,日活跃用户,月活跃用户,页面浏览量,独立访客数,平均会话时长,用户来源渠道,转化率,留存率\n2024-10-01,161,2476,17014,13657,2532,11.6,直接访问,5.5,46.5\n2024-10-02,176,2669,17293,17033,2791,9,搜索引擎,6.4,42.9\n2024-10-03,171,2555,16403,16554,2740,7.4,搜索引擎,6.7,53.7\n2024-10-04,206,2944,20657,18795,3308,11.3,邮件营销,7.1,52.8\n2024-10-05,211,3322,23503,17887,3872,7.8,社交媒体,6.5,42.7\n2024-10-06,240,3526,24424,18717,4040,9.7,搜索引擎,4.5,44.2\n2024-10-07,215,3379,21741,21502,4030,11.6,搜索引擎,3.9,41.9\n2024-10-08,237,3617,25933,24085,4352,11.4,直接访问,5.9,43.8\n2024-10-09,256,3851,29626,23660,4512,7.9,社交媒体,5.8,44.1\n2024-10-10,278,4260,30062,26817,4660,10.5,搜索引擎,6.5,47.8\n2024-10-11,303,4612,29919,26495,5136,9.5,邮件营销,7.1,46.8\n2024-10-12,320,4723,36068,31769,4725,12.4,搜索引擎,4.2,54.1\n2024-10-13,342,5219,36547,33161,5225,9.3,直接访问,7,41.5\n2024-10-14,426,6681,49425,36419,7885,9.9,搜索引擎,5.5,53.1\n2024-10-15,436,6353,48445,43205,7360,9.5,社交媒体,3.4,54.5\n2024-10-16,449,6990,46139,37032,6938,12.9,邮件营销,3.6,47.3\n2024-10-17,541,7950,60192,47855,8035,12.9,搜索引擎,4.1,48.8\n2024-10-18,598,9321,61491,61995,10662,10.7,搜索引擎,4.8,47\n2024-10-19,647,9805,75107,62883,10290,11.1,搜索引擎,4.5,55.7\n2024-10-20,680,10109,73658,61221,11395,13.8,搜索引擎,4.8,49.8\n2024-10-21,703,10941,74864,75790,11417,11.5,搜索引擎,5.9,47.4\n2024-10-22,693,10068,64616,51492,10456,8.5,邮件营销,4.9,44.3\n2024-10-23,846,12417,89895,64515,14228,10.7,推荐链接,4.7,43\n2024-10-24,950,14881,100486,90555,15794,9.8,搜索引擎,7.6,46.1\n2024-10-25,918,13181,94740,66528,13668,14.8,社交媒体,7.7,43.6\n2024-10-26,1075,16686,120655,110830,19628,9.6,社交媒体,3.5,58.2\n2024-10-27,1193,18003,115140,100009,18305,12.7,直接访问,6.2,47.6\n2024-10-28,1241,18849,120490,122785,19186,15.2,搜索引擎,4.3,49.1\n2024-10-29,1186,17325,112029,124497,20279,13.3,直接访问,6.3,49.9\n2024-10-30,1453,22552,164957,140682,26023,11.7,搜索引擎,6,46.2\n', '雷达图', '{\n  \"title\": {\"text\": \"网站核心指标增长趋势（2024年10月）\"},\n  \"tooltip\": {\"trigger\": \"axis\"},\n  \"legend\": {\"data\": [\"新注册用户数\", \"日活跃用户\", \"页面浏览量\", \"独立访客数\"]},\n  \"xAxis\": {\n    \"type\": \"category\",\n    \"data\": [\n      \"2024-10-01\",\"2024-10-02\",\"2024-10-03\",\"2024-10-04\",\"2024-10-05\",\n      \"2024-10-06\",\"2024-10-07\",\"2024-10-08\",\"2024-10-09\",\"2024-10-10\",\n      \"2024-10-11\",\"2024-10-12\",\"2024-10-13\",\"2024-10-14\",\"2024-10-15\",\n      \"2024-10-16\",\"2024-10-17\",\"2024-10-18\",\"2024-10-19\",\"2024-10-20\",\n      \"2024-10-21\",\"2024-10-22\",\"2024-10-23\",\"2024-10-24\",\"2024-10-25\",\n      \"2024-10-26\",\"2024-10-27\",\"2024-10-28\",\"2024-10-29\",\"2024-10-30\"\n    ]\n  },\n  \"yAxis\": {\"type\": \"value\"},\n  \"series\": [\n    {\n      \"name\": \"新注册用户数\",\n      \"type\": \"line\",\n      \"data\": [161,176,171,206,211,240,215,237,256,278,303,320,342,426,436,449,541,598,647,680,703,693,846,950,918,1075,1193,1241,1186,1453]\n    },\n    {\n      \"name\": \"日活跃用户\",\n      \"type\": \"line\",\n      \"data\": [2476,2669,2555,2944,3322,3526,3379,3617,3851,4260,4612,4723,5219,6681,6353,6990,7950,9321,9805,10109,10941,10068,12417,14881,13181,16686,18003,18849,17325,22552]\n    },\n    {\n      \"name\": \"页面浏览量\",\n      \"type\": \"line\",\n      \"data\": [13657,17033,16554,18795,17887,18717,21502,24085,23660,26817,26495,31769,33161,36419,43205,37032,47855,61995,62883,61221,75790,51492,64515,90555,66528,110830,100009,122785,124497,140682]\n    },\n    {\n      \"name\": \"独立访客数\",\n      \"type\": \"line\",\n      \"data\": [2532,2791,2740,3308,3872,4040,4030,4352,4512,4660,5136,4725,5225,7885,7360,6938,8035,10662,10290,11395,11417,10456,14228,15794,13668,19628,18305,19186,20279,26023]\n    }\n  ]\n}', '通过对2024年10月1日至10月30日网站增长数据的分析，可以得出以下关键结论：\n1. **整体增长趋势显著**：新注册用户数从161（10月1日）增长至1453（10月30日），增幅高达802%，呈现出持续且加速的增长态势。日活跃用户（DAU）从2476增至22552，增长近8倍，表明用户参与度大幅提升。\n2. **关键增长节点明显**：10月中旬（10月14日-10月17日）和10月下旬（10月26日-10月30日）是两个明显的增长高峰。特别是在10月26日之后，新注册用户突破千人，日活跃用户突破1.6万，页面浏览量和独立访客数也同步跃升。\n3. **用户来源渠道分析**：“搜索引擎”是最主要的流量来源，贯穿整月高频出现，尤其在关键增长期贡献显著；“社交媒体”和“直接访问”在中后期表现活跃，说明品牌认知和口碑传播开始起效；“邮件营销”虽频率较低，但在特定日期（如10月12日、10月16日）带来较高转化率（7.1%），具备精准触达能力。\n4. **用户行为与质量稳定**：平均会话时长整体维持在9-15分钟区间，最高达15.2分钟（10月28日），说明内容吸引力较强。转化率波动较大（3.4%-7.7%），但高增长日多伴随中等转化率（5%-7%），未因流量激增而明显下降。留存率保持在40%-60%之间，部分日期（如10月26日达58.2%）表现优异，显示用户粘性良好。\n5. **规模效应显现**：月活跃用户（MAU）从1.7万增长至16.5万，增长近10倍，MAU/DAU比值从约6.9降至7.3，用户使用频次相对稳定，平台已进入快速扩张阶段。\n综上，网站正处于高速增长期，用户规模、活跃度和内容消费深度均持续提升，建议加强搜索引擎优化（SEO/SEM）、扩大社交媒体运营投入，并对高转化渠道进行精细化运营以进一步释放增长潜力', 1980102090143301634, NULL, '2025-10-31 21:12:11', '2025-11-02 15:58:52', 0);
INSERT INTO `chart` VALUES (1984496420524191745, '用户分析增长', '分析用户情况', 'wait', '日期,新注册用户数,日活跃用户,月活跃用户,页面浏览量,独立访客数,平均会话时长,用户来源渠道,转化率,留存率\n2024-10-01,161,2476,17014,13657,2532,11.6,直接访问,5.5,46.5\n2024-10-02,176,2669,17293,17033,2791,9,搜索引擎,6.4,42.9\n2024-10-03,171,2555,16403,16554,2740,7.4,搜索引擎,6.7,53.7\n2024-10-04,206,2944,20657,18795,3308,11.3,邮件营销,7.1,52.8\n2024-10-05,211,3322,23503,17887,3872,7.8,社交媒体,6.5,42.7\n2024-10-06,240,3526,24424,18717,4040,9.7,搜索引擎,4.5,44.2\n2024-10-07,215,3379,21741,21502,4030,11.6,搜索引擎,3.9,41.9\n2024-10-08,237,3617,25933,24085,4352,11.4,直接访问,5.9,43.8\n2024-10-09,256,3851,29626,23660,4512,7.9,社交媒体,5.8,44.1\n2024-10-10,278,4260,30062,26817,4660,10.5,搜索引擎,6.5,47.8\n2024-10-11,303,4612,29919,26495,5136,9.5,邮件营销,7.1,46.8\n2024-10-12,320,4723,36068,31769,4725,12.4,搜索引擎,4.2,54.1\n2024-10-13,342,5219,36547,33161,5225,9.3,直接访问,7,41.5\n2024-10-14,426,6681,49425,36419,7885,9.9,搜索引擎,5.5,53.1\n2024-10-15,436,6353,48445,43205,7360,9.5,社交媒体,3.4,54.5\n2024-10-16,449,6990,46139,37032,6938,12.9,邮件营销,3.6,47.3\n2024-10-17,541,7950,60192,47855,8035,12.9,搜索引擎,4.1,48.8\n2024-10-18,598,9321,61491,61995,10662,10.7,搜索引擎,4.8,47\n2024-10-19,647,9805,75107,62883,10290,11.1,搜索引擎,4.5,55.7\n2024-10-20,680,10109,73658,61221,11395,13.8,搜索引擎,4.8,49.8\n2024-10-21,703,10941,74864,75790,11417,11.5,搜索引擎,5.9,47.4\n2024-10-22,693,10068,64616,51492,10456,8.5,邮件营销,4.9,44.3\n2024-10-23,846,12417,89895,64515,14228,10.7,推荐链接,4.7,43\n2024-10-24,950,14881,100486,90555,15794,9.8,搜索引擎,7.6,46.1\n2024-10-25,918,13181,94740,66528,13668,14.8,社交媒体,7.7,43.6\n2024-10-26,1075,16686,120655,110830,19628,9.6,社交媒体,3.5,58.2\n2024-10-27,1193,18003,115140,100009,18305,12.7,直接访问,6.2,47.6\n2024-10-28,1241,18849,120490,122785,19186,15.2,搜索引擎,4.3,49.1\n2024-10-29,1186,17325,112029,124497,20279,13.3,直接访问,6.3,49.9\n2024-10-30,1453,22552,164957,140682,26023,11.7,搜索引擎,6,46.2\n', 'pie', '{\n  \"title\": {\"text\": \"用户来源渠道分布\", \"left\": \"center\"},\n  \"tooltip\": {\"trigger\": \"item\"},\n  \"legend\": {\"orient\": \"vertical\", \"left\": \"left\", \"bottom\": 0},\n  \"series\": [{\n    \"name\": \"用户来源\",\n    \"type\": \"pie\",\n    \"radius\": \"50%\",\n    \"data\": [\n      {\"value\": 12, \"name\": \"搜索引擎\"},\n      {\"value\": 5, \"name\": \"直接访问\"},\n      {\"value\": 4, \"name\": \"社交媒体\"},\n      {\"value\": 4, \"name\": \"邮件营销\"},\n      {\"value\": 1, \"name\": \"推荐链接\"}\n    ],\n    \"emphasis\": {\"itemStyle\": {\"shadowBlur\": 10, \"shadowOffsetX\": 0, \"shadowColor\": \"rgba(0, 0, 0, 0.5)\"}}\n  }]\n}', '从2024年10月1日至10月30日的用户数据来看，整体用户规模呈现显著上升趋势。新注册用户数从最初的161人增长至1453人，增幅高达802.5%，尤其在10月下旬连续多日突破千人，表明市场推广或产品吸引力显著增强。日活跃用户（DAU）从2476增长至22552，增长近8倍，且与新用户增长趋势高度一致，说明新增用户有效转化为活跃用户。\n月活跃用户（MAU）从17014增长至164957，增幅超过870%，反映出用户基数快速扩张。页面浏览量和独立访客数也同步大幅上升，分别从13657增至140682和2532增至26023，说明用户参与度和平台内容消费能力持续提升。平均会话时长整体维持在较高水平，最高达15.2分钟（10月28日），最低为7.4分钟，波动较小，用户粘性较为稳定。\n用户来源渠道分析显示，“搜索引擎”是最主要的流量来源，出现频率最高，尤其是在高增长阶段占据主导；“直接访问”和“社交媒体”次之，其中“社交媒体”在转化率方面表现突出，部分日期达到7.7%；而“邮件营销”虽然流量相对稳定，但转化率波动较大。整体转化率在3.4%~7.7%之间波动，最高出现在社交媒体渠道，说明其营销内容更具说服力。留存率整体保持在41%~58%之间，10月26日达到峰值58.2%，表明用户忠诚度较高，尤其在大规模获客后仍能维持良好留存，体现出较强的产品黏性和用户体验。\n综合判断：平台正处于高速增长期，用户获取效率高，活跃度与粘性良好，建议继续加大在搜索引擎和社交媒体渠道的投入，同时优化邮件营销策略以提升转化效果，并关注高增长后的用户留存质量', 1980102090143301634, NULL, '2025-11-01 13:43:11', '2025-11-04 11:02:14', 0);
INSERT INTO `chart` VALUES (1984890912179793921, '测试表', '分析目标网站用户的情况', 'wait', '日期,新注册用户数,日活跃用户,月活跃用户,页面浏览量,独立访客数,平均会话时长,用户来源渠道,转化率,留存率\n2024-10-01,161,2476,17014,13657,2532,11.6,直接访问,5.5,46.5\n2024-10-02,176,2669,17293,17033,2791,9,搜索引擎,6.4,42.9\n2024-10-03,171,2555,16403,16554,2740,7.4,搜索引擎,6.7,53.7\n2024-10-04,206,2944,20657,18795,3308,11.3,邮件营销,7.1,52.8\n2024-10-05,211,3322,23503,17887,3872,7.8,社交媒体,6.5,42.7\n2024-10-06,240,3526,24424,18717,4040,9.7,搜索引擎,4.5,44.2\n2024-10-07,215,3379,21741,21502,4030,11.6,搜索引擎,3.9,41.9\n2024-10-08,237,3617,25933,24085,4352,11.4,直接访问,5.9,43.8\n2024-10-09,256,3851,29626,23660,4512,7.9,社交媒体,5.8,44.1\n2024-10-10,278,4260,30062,26817,4660,10.5,搜索引擎,6.5,47.8\n2024-10-11,303,4612,29919,26495,5136,9.5,邮件营销,7.1,46.8\n2024-10-12,320,4723,36068,31769,4725,12.4,搜索引擎,4.2,54.1\n2024-10-13,342,5219,36547,33161,5225,9.3,直接访问,7,41.5\n2024-10-14,426,6681,49425,36419,7885,9.9,搜索引擎,5.5,53.1\n2024-10-15,436,6353,48445,43205,7360,9.5,社交媒体,3.4,54.5\n2024-10-16,449,6990,46139,37032,6938,12.9,邮件营销,3.6,47.3\n2024-10-17,541,7950,60192,47855,8035,12.9,搜索引擎,4.1,48.8\n2024-10-18,598,9321,61491,61995,10662,10.7,搜索引擎,4.8,47\n2024-10-19,647,9805,75107,62883,10290,11.1,搜索引擎,4.5,55.7\n2024-10-20,680,10109,73658,61221,11395,13.8,搜索引擎,4.8,49.8\n2024-10-21,703,10941,74864,75790,11417,11.5,搜索引擎,5.9,47.4\n2024-10-22,693,10068,64616,51492,10456,8.5,邮件营销,4.9,44.3\n2024-10-23,846,12417,89895,64515,14228,10.7,推荐链接,4.7,43\n2024-10-24,950,14881,100486,90555,15794,9.8,搜索引擎,7.6,46.1\n2024-10-25,918,13181,94740,66528,13668,14.8,社交媒体,7.7,43.6\n2024-10-26,1075,16686,120655,110830,19628,9.6,社交媒体,3.5,58.2\n2024-10-27,1193,18003,115140,100009,18305,12.7,直接访问,6.2,47.6\n2024-10-28,1241,18849,120490,122785,19186,15.2,搜索引擎,4.3,49.1\n2024-10-29,1186,17325,112029,124497,20279,13.3,直接访问,6.3,49.9\n2024-10-30,1453,22552,164957,140682,26023,11.7,搜索引擎,6,46.2\n', '饼图', '{\n  \"title\": {\"text\": \"日活跃用户与新注册用户趋势图（2024年10月）\"},\n  \"tooltip\": {\"trigger\": \"axis\"},\n  \"legend\": {\"data\": [\"新注册用户数\", \"日活跃用户\"]},\n  \"xAxis\": {\"type\": \"category\", \"data\": [\"2024-10-01\", \"2024-10-02\", \"2024-10-03\", \"2024-10-04\", \"2024-10-05\", \"2024-10-06\", \"2024-10-07\", \"2024-10-08\", \"2024-10-09\", \"2024-10-10\", \"2024-10-11\", \"2024-10-12\", \"2024-10-13\", \"2024-10-14\", \"2024-10-15\", \"2024-10-16\", \"2024-10-17\", \"2024-10-18\", \"2024-10-19\", \"2024-10-20\", \"2024-10-21\", \"2024-10-22\", \"2024-10-23\", \"2024-10-24\", \"2024-10-25\", \"2024-10-26\", \"2024-10-27\", \"2024-10-28\", \"2024-10-29\", \"2024-10-30\"]},\n  \"yAxis\": {\"type\": \"value\", \"name\": \"用户数量\"},\n  \"series\": [\n    {\n      \"name\": \"新注册用户数\",\n      \"type\": \"line\",\n      \"data\": [161, 176, 171, 206, 211, 240, 215, 237, 256, 278, 303, 320, 342, 426, 436, 449, 541, 598, 647, 680, 703, 693, 846, 950, 918, 1075, 1193, 1241, 1186, 1453]\n    },\n    {\n      \"name\": \"日活跃用户\",\n      \"type\": \"line\",\n      \"data\": [2476, 2669, 2555, 2944, 3322, 3526, 3379, 3617, 3851, 4260, 4612, 4723, 5219, 6681, 6353, 6990, 7950, 9321, 9805, 10109, 10941, 10068, 12417, 14881, 13181, 16686, 18003, 18849, 17325, 22552]\n    }\n  ]\n}', '通过对目标网站2024年10月全月的用户行为数据进行分析，可以得出以下关键结论：\n1. **用户规模持续增长**：新注册用户数从10月1日的161人稳步上升至10月30日的1453人，整体呈现指数级增长趋势，尤其是在10月下旬增速显著加快，表明市场推广或渠道投放策略取得明显成效。\n2. **活跃用户同步提升**：日活跃用户（DAU）由月初的2476增长至22552，增幅超过8倍；月活跃用户（MAU）从17014增长至164957，增长近9倍。DAU/MAU比率维持在13%-14%区间，符合成熟互联网产品的活跃水平，说明用户粘性较为稳定。\n3. **流量来源集中于“搜索引擎”**：数据显示“搜索引擎”是主要用户来源渠道，出现频率最高且伴随大规模用户增长阶段，尤其在10月下旬多次主导新增和活跃用户高峰，显示出SEO或SEM策略效果显著。\n4. **转化率波动但整体可控**：转化率在3.4%~7.7%之间波动，最高出现在社交媒体渠道（7.7%），最低为搜索引擎（部分日期低至3.9%）。尽管搜索引擎带来最大流量，但其转化效率偏低，存在优化空间。\n5. **留存率保持健康水平**：用户留存率在41.5%~58.2%之间波动，整体维持在45%以上，其中10月26日达到峰值58.2%，对应社交媒体渠道的大规模引流，表明该渠道用户质量较高、更具忠诚度。\n6. **用户参与度良好**：平均会话时长普遍在9~15分钟之间，最高达15.2分钟（10月28日），结合页面浏览量与独立访客数同步增长，说明内容吸引力较强，用户体验较好。\n7. **关键增长节点识别**：10月23日后出现明显的拐点式增长，可能与特定营销活动、广告投放或产品更新有关，建议进一步追溯运营动作以复制成功经验。\n综上所述，网站正处于高速增长期，用户基础快速扩大，活跃度和参与度表现良好，但需关注高流量渠道（如搜索引擎）的转化效率提升，并强化高留存渠道（如社交媒体、邮件营销）的资源倾斜', 1980102090143301634, NULL, '2025-11-02 15:50:46', '2025-11-02 15:57:41', 0);
