r\": \"{a} <br/>{b} : {c}\"},\n  \"legend\": {\"data\": [\"新注册用户数\", \"日活跃用户\", \"页面浏览量\", \"独立访客数\"], \"bottom\": 0},\n  \"xAxis\": {\"type\": \"value\", \"scale\": true},\n  \"yAxis\": {\"type\": \"value\", \"scale\": true},\n  \"series\": [\n    {\n      \"name\": \"新注册用户数\",\n      \"type\": \"scatter\",\n      \"data\": [[161,2476],[176,2669],[171,2555],[206,2944],[211,3322],[240,3526],[215,3379],[237,3617],[256,3851],[278,4260],[303,4612],[320,4723],[342,5219],[426,6681],[436,6353],[449,6938],[541,7950],[598,9321],[647,9805],[680,10109],[703,10941],[693,10068],[846,12417],[950,14881],[918,13181],[1075,16686],[1193,18003],[1241,18849],[1186,17325],[1453,22552]],\n      \"symbolSize\": 10,\n      \"itemStyle\": {\"color\": \"#5470c6\"}\n    },\n    {\n      \"name\": \"日活跃用户\",\n      \"type\": \"scatter\",\n      \"data\": [[2476,13657],[2669,17033],[2555,16554],[2944,18795],[3322,17887],[3526,18717],[3379,21502],[3617,24085],[3851,23660],[4260,26817],[4612,26495],[4723,31769],[5219,33161],[6681,36419],[6353,43205],[6938,37032],[7950,47855],[9321,61995],[9805,62883],[10109,61221],[10941,75790],[10068,51492],[12417,64515],[14881,90555],[13181,66528],[16686,110830],[18003,100009],[18849,122785],[17325,124497],[22552,140682]],\n      \"symbolSize\": 10,\n      \"itemStyle\": {\"color\": \"#91cc75\"}\n    },\n    {\n      \"name\": \"页面浏览量\",\n      \"type\": \"scatter\",\n      \"data\": [[13657,2532],[17033,2791],[16554,2740],[18795,3308],[17887,3872],[18717,4040],[21502,4030],[24085,4352],[23660,4512],[26817,4660],[26495,5136],[31769,4725],[33161,5225],[36419,7885],[43205,7360],[37032,6938],[47855,8035],[61995,10662],[62883,10290],[61221,11395],[75790,11417],[51492,10456],[64515,14228],[90555,15794],[66528,13668],[110830,19628],[100009,18305],[122785,19186],[124497,20279],[140682,26023]],\n      \"symbolSize\": 10,\n      \"itemStyle\": {\"color\": \"#fac858\"}\n    },\n    {\n      \"name\": \"独立访客数\",\n      \"type\": \"scatter\",\n      \"data\": [[2532,11.6],[2791,9],[2740,7.4],[3308,11.3],[3872,7.8],[4040,9.7],[4030,11.6],[4352,11.4],[4512,7.9],[4660,10.5],[5136,9.5],[4725,12.4],[5225,9.3],[7885,9.9],[7360,9.5],[6938,12.9],[8035,12.9],[10662,10.7],[10290,11.1],[11395,13.8],[11417,11.5],[10456,8.5],[14228,10.7],[15794,9.8],[13668,14.8],[19628,9.6],[18305,12.7],[19186,15.2],[20279,13.3],[26023,11.7]],\n      \"symbolSize\": 10,\n      \"itemStyle\": {\"color\": \"#ee6666\"}\n    }\n  ],\n  \"grid\": {\"left\": \"3%\", \"right\": \"4%\", \"bottom\": \"12%\", \"containLabel\": true}\n}', '从2024年10月1日至10月30日的网站用户数据来看，整体用户规模呈现显著增长趋势。新注册用户数从初期的161人稳步上升至1453人（10月30日），累计增长近8倍，尤其在10月下旬增长加速，表明市场推广或渠道投放策略取得明显成效。日活跃用户（DAU）从2476增长至22552，增幅达810%，反映出用户参与度大幅提升；月活跃用户（MAU）也从17014增至164957，说明用户基础持续扩大。\n页面浏览量和独立访客数同步快速增长，分别从13657提升至140682（增长约9.3倍）和2532增至26023（增长约9.3倍），两者变化趋势高度一致，说明流量增长主要来源于真实用户访问而非机器流量。平均会话时长整体维持在9-15分钟之间波动，最高达到15.2分钟（10月28日），表明内容吸引力较强且用户体验良好。\n用户来源渠道分析显示，“搜索引擎”是最主要的流量来源，出现在多数高增长日期中，尤其是在中后期占据主导地位；“社交媒体”和“直接访问”在部分关键节点（如10月26日、10月27日）贡献了大量新增用户，显示出品牌传播效应初现。转化率整体在3.4%~7.7%之间波动，尽管流量大幅增加，但转化率未出现显著下降，说明流量质量保持稳定。留存率在41.5%~58.2%之间波动，其中10月26日达到峰值58.2%，表明当日获取的用户具有极高粘性，可能与特定营销活动有关。\n综合来看，网站正处于高速增长阶段，用户获取能力显著增强，用户活跃度和粘性保持良好水平，建议进一步优化高转化渠道（如邮件营销、社交媒体）的投入比例，并深入分析高留存日期的运营动作以复制成功经验', 1980102090143301634, NULL, '2025-11-04 11:00:11', '2025-11-04 11:00:11', 0);

-- ----------------------------
-- Table structure for user
-- ----------------------------
DROP TABLE IF EXISTS `user`;
CREATE TABLE `user`  (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT 'id',
  `userAccount` varchar(256) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '账号',
  `userPassword` varchar(512) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '密码',
  `userName` varchar(256) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '用户昵称',
  `userAvatar` varchar(1024) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '用户头像',
  `userRole` varchar(256) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'user' COMMENT '用户角色：user/admin',
  `createTime` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `updateTime` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  `isDelete` tinyint NOT NULL DEFAULT 0 COMMENT '是否删除',
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `idx_userAccount`(`userAccount`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 1980102090143301635 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_unicode_ci COMMENT = '用户' ROW_FORMAT = Dynamic;

-- ----------------------------
